import { useEffect, useRef, useState } from "react"
import { useAuth } from "../../Context/useAuth";
import { MoonLoader } from "react-spinners";
import { addReply, getPostReplies } from "../../../API/Api";
import { useInfiniteQuery, useQueryClient } from "@tanstack/react-query";
import { handleClickProfile } from "../../../helpers/handleClicks";
import { useNavigate } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import VerifiedBadge from "../Badge/VerifiedBadge";
import formatPostDate from "../../../helpers/formatDateString";
import ReplyContextChip from "./ReplyContextChip";
import useTextareaMention from "../mentions/useTextareaMention";
import MentionDropdown from "../mentions/MentionDropdown";

const incrementReplyCount = (old, parentId) => {
    if (!old || !Array.isArray(old.pages)) return old;

    return {
        ...old,
        pages: old.pages.map((page) => ({
            ...page,
            comments: Array.isArray(page?.comments)
                ? page.comments.map((comment) => {
                    if (comment?.id !== parentId) return comment;
                    return {
                        ...comment,
                        reply_count: (comment?.reply_count || 0) + 1,
                    };
                })
                : page?.comments,
        })),
    };
};


const CommentsCards = ({comments, postId}) =>{
    const {user, session} = useAuth();
    const userId = user?.userData[0].id;
    const queryClient = useQueryClient();

    const [showReplyInput, setShowReplyInput] = useState(false);
    const [showReplies, setShowReplies] = useState(false);

    const [reply, setReply] = useState('')
    const [replyLoaderId, setReplyLoaderId] = useState('');

    const navigate = useNavigate();
    const replyInputRef = useRef(null);

    const { textareaProps: mentionTextareaProps, dropdownProps: mentionDropdownProps } = useTextareaMention(reply, setReply, replyInputRef, 200, userId);

    const clickProfile = handleClickProfile(navigate);

    const {data, isLoading, fetchNextPage, hasNextPage, isFetchinNextPage} = useInfiniteQuery({
        queryKey: ['getPostReplies', comments.id],
        queryFn: ({pageParam = null, queryKey}) => getPostReplies(queryKey[1], 5, pageParam),
        getNextPageParam: (lastPage) => {
            if(lastPage.hasMore){
                const lastReply = lastPage?.data[lastPage?.data.length - 1];
                return lastReply.id;
            } else{
                return undefined
            }
        },
        refetchOnWindowFocus: false,
        enabled: showReplies,
        staleTime: 1000 * 60 * 5
    })

    const handleClickReplyButton = (e) =>{
        e.stopPropagation();
        setShowReplyInput(!showReplyInput);
    }

    const handleShowMoreReplies = () => {
        if(!isFetchinNextPage){
            fetchNextPage();
        }
    }

    const submitReply = async(parent_id, receiver_id) => {
        const trimmedReply = reply.trim();
        if (!trimmedReply) return;

        setReplyLoaderId(parent_id)
        queryClient.cancelQueries({ queryKey: ['getPostReplies', parent_id] });
        queryClient.cancelQueries({ queryKey: ['postComments', postId] });

        const previousReplies = queryClient.getQueryData(['getPostReplies', parent_id]);
        const previousComments = queryClient.getQueryData(['postComments', postId]);

        const optimisticReply = {
            id: `optimistic-reply-${Date.now()}`,
            post_id: postId,
            parent_id: parent_id,
            comment: trimmedReply,
            created_at: new Date().toISOString(),
            user_id: user?.userData?.[0]?.id,
            users: {
                id: user?.userData?.[0]?.id,
                name: user?.userData?.[0]?.name,
                image_url: user?.userData?.[0]?.image_url,
                badge: user?.userData?.[0]?.badge,
            },
            reply_count: 0,
        };

        queryClient.setQueryData(['getPostReplies', parent_id], (old) => {
            if (!old || !Array.isArray(old.pages)) {
                return {
                    pageParams: [null],
                    pages: [{ data: [optimisticReply], hasMore: false }],
                };
            }

            return {
                ...old,
                pages: old.pages.map((page, index) =>
                    index === 0
                        ? { ...page, data: [optimisticReply, ...(page?.data || [])] }
                        : page
                ),
            };
        });
        queryClient.setQueryData(['postComments', postId], (old) => incrementReplyCount(old, parent_id));

        try {
            const formdata = new FormData();
            formdata.append('reply', trimmedReply);

            const message = await addReply(userId, postId, parent_id, formdata, receiver_id, session?.access_token);
            if(message){
                // console.log(message);
            }
            queryClient.invalidateQueries({ queryKey: ['getPostReplies', parent_id] });
            queryClient.invalidateQueries({ queryKey: ['postComments', postId] });
            setReply('')
            setShowReplies(true)
        } catch (error) {
            queryClient.setQueryData(['getPostReplies', parent_id], previousReplies);
            queryClient.setQueryData(['postComments', postId], previousComments);
            setReply('')
            throw new Error('error adding replies')
        } finally {
            setReplyLoaderId('')
            setShowReplyInput(false);
        }
    }

    useEffect(() =>{
        if(showReplyInput && replyInputRef.current){
            const timer = setTimeout(() => {
                replyInputRef.current.focus();
                replyInputRef.current.scrollIntoView({behavior: 'smooth', block: 'center'})
            }, 50);

            return () => {
                clearTimeout(timer)
            }
        }
    }, [showReplyInput])

    const replies = data?.pages.flatMap((page) => page.data) || [];

    return(
        <div className={`cm-card ${comments?.parent_id ? 'cm-card--reply' : ''}`}>
            {comments?.parent_id && <div className="cm-thread-line" />}

            <div className="cm-card-content">
                <div className="cm-user-row">
                    <div
                        onClick={(e) => clickProfile(e, user?.userData[0].id, comments?.user_id)}
                        className={`cm-avatar-container ${comments?.users?.badge === 'legend' ? 'cm-ring-legend' : comments?.users?.badge === 'og' ? 'cm-ring-og' : ''}`}
                    >
                        <img className="cm-avatar" src={comments?.users?.image_url || '/assets/profile.jpg'} alt={`${comments?.users?.name || "User"} profile picture`} />
